import { assertObject } from '../helpers/object-utils';
import { createModel } from '../schema';
import { SliceContext } from './models';

/** Skip validation in production for performance */
const IS_PRODUCTION = process.env.NODE_ENV === 'production';

export namespace Context {
  export const Model = createModel({
    userID: {
      union: [
        'string',
        'number',
        'null',
        'undefined',
      ],
    },
  });

  export function Assert(value: unknown): asserts value is SliceContext {
    if (Model.isValid(value) && 'userID' in value) return;
    throw new Error(`Invalid value received for context.`);
  }

  export function Handler(slicesContext: SliceContext) {
    let current = slicesContext;

    const check = (value: unknown): SliceContext => {
      if (IS_PRODUCTION) {
        return value as SliceContext;
      }
      assertObject(value, `Expected value to be an object.`);
      Assert(value);
      return value;
    };

    return {
      get() {
        return check(current);
      },
      assign(value: Partial<SliceContext>) {
        current = check({
          ...current,
          ...value,
        });
      },
    };
  }
}

import { MSTimeString } from '../../helpers/ms';

/**
 * Defines the cache invalidation policy and scope.
 */
export enum CachePolicy {
  /**
   * Public, shared cache. Invalidated only by its TTL.
   * Ideal for global data that rarely changes.
   * E.g., Plan prices, feature flag configurations.
   */
  public = 'public',

  /**
   * Private cache, bound to the user session.
   * Invalidated on logout/login OR when TTL expires.
   * E.g., User profile data, permissions.
   */
  private = 'private',

  /**
   * App session cache. Persists while the app is active.
   * Invalidated on app close/reopen OR when TTL expires.
   * E.g., Data for a specific screen that doesn't need to persist.
   */
  session = 'session',
}

/**
 * Defines the caching behavior for a slice.
 */
export type CacheStrategy = {
  /**
   * Policy defining the cache's lifecycle and scope.
   * Cache is invalidated by the policy's event OR TTL expiry, whichever comes first.
   * @default 'private'
   */
  policy: keyof typeof CachePolicy;
  /**
   * Time-To-Live (TTL). Maximum cache lifespan (e.g., '1h', '30m').
   * A TTL of 0 means the cache expires immediately, forcing revalidation.
   */
  ttl?: MSTimeString;
  /**
   * Stale-While-Revalidate (SWR).
   * If true, returns cached data (even if stale) while revalidating in the background.
   * If false and the cache is invalid, it will wait for the fresh data fetch.
   * @default true
   */
  swr?: boolean;
};

export type CacheStrategyField = keyof CacheStrategy & {};

import {
  AnyRecord,
  AsString,
  Cast,
  Compute,
  Merge,
  Paths,
  PathType,
  Writable,
} from '../../helpers/type-utils';

import {
  AnyAsyncSlice,
  CombineSlicesState,
  ExtractSelectorValues,
  MachineSelectors,
  MachineSlices,
  SliceToActionCreators,
} from './commons';

import { SliceKind } from './slice';

/**
 * Defines the overloaded signature for the `useMachine` hook, allowing it to
 * select state from sync slices/selectors or interact with async slices.
 */

export type MachineHook<
  Slices extends MachineSlices,
  Selectors extends MachineSelectors<any>,
> = RootSelector<Slices, MergeAll<Slices, Selectors>, AsString<keyof Slices>>;

export type MachineUseSelector<State> = <T>(select: (state: State) => T) => T;

type MergeAll<
  Slices extends MachineSlices,
  Selectors extends MachineSelectors<any>,
> = Merge<
  Merge<
    CombineSlicesState<OnlyAsyncSlices<Slices>>,
    CombineSlicesState<OnlySyncSlices<Slices>>
  >,
  Compute<Writable<ExtractSelectorValues<Selectors>>>
>;

export type SliceRooks<Slice> = {
  [K in keyof SliceToActionCreators<Slice>]: SliceToActionCreators<Slice>[K] extends (
    ...args: infer Args
  ) => any
    ? (...args: Cast<Args, any[]>) => void
    : never;
};

/**
 * Selector return type. Returns { state, actions } for slices.
 */
type RootSelector<
  Slices extends MachineSlices,
  RootState extends AnyRecord,
  SliceKey extends keyof Slices,
> = {
  <P extends Paths<RootState>>(
    path: P,
  ): P extends SliceKey
    ? {
        state: Compute<RootState[P]>;
        actions: SliceRooks<Slices[P]>;
      }
    : PathType<RootState, P>;
};

type OnlyAsyncSlices<Slices extends MachineSlices> = {
  [K in keyof Slices as [Slices[K]['kind']] extends [SliceKind.async]
    ? K
    : never]: Cast<Slices[K], AnyAsyncSlice>;
};

type OnlySyncSlices<Slices extends MachineSlices> = {
  [K in keyof Slices as [Slices[K]['kind']] extends [SliceKind.sync]
    ? K
    : never]: Slices[K];
};

