import {
  CombineSlicesContext,
  CombineSlicesState,
  MachineConfig,
  MachineSelectors,
  MachineSlices,
} from './models';

export function createMachineConfig<
  const Slices extends MachineSlices,
  const Selectors extends MachineSelectors<CombineSlicesState<Slices>>,
  const State extends CombineSlicesState<Slices>,
  const Context extends CombineSlicesContext<Slices>,
  const ID extends string,
>(
  config: MachineConfig<Slices, State, Selectors, Context, ID>,
): MachineConfig<Slices, State, Selectors, Context, ID> {
  return config;
}

export function basicRandomID() {
  const now = Date.now();
  const time = now.toString(36).padStart(9, '0');
  const suffix = Math.random().toString(36).substring(2);
  return `${time}${suffix}`;
}

export const GLOBAL_APP_SESSION_ID = basicRandomID();

